// src/App.jsx  (or App.js)

import React from "react";
import { BrowserRouter as Router, Routes, Route } from "react-router-dom";

// Import your pages
import HospitalListing from "./pages/HospitalListing";
import DoctorsList from "./pages/DoctorsList";
import DoctorProfile from "./pages/DoctorProfile";

// Optional: Add a simple Navbar or layout later
// import Navbar from './components/Navbar';

function App() {
  return (
    <Router>
      <div style={{ backgroundColor: "#f5f5f5", minHeight: "100vh" }}>
        {/* <Navbar /> */} {/* Uncomment later when you add a navbar */}
        <Routes>
          {/* Home page - shows list of hospitals */}
          <Route path="/" element={<HospitalListing />} />

          {/* Doctors list for a specific hospital */}
          <Route
            path="/hospital/:hospitalId/doctors"
            element={<DoctorsList />}
          />

          {/* Detailed profile of one doctor */}
          <Route path="/doctor/:doctorId" element={<DoctorProfile />} />

          {/* Optional: 404 / fallback route */}
          <Route
            path="*"
            element={
              <div style={{ textAlign: "center", padding: "100px 20px" }}>
                <h2>Page Not Found</h2>
                <p>Sorry, the page you're looking for doesn't exist.</p>
              </div>
            }
          />
        </Routes>
      </div>
    </Router>
  );
}

export default App;
